<template><el-container class="layout-container"><el-aside width="248px" class="layout-aside"><div class="brand"><div class="brand-mark"><el-icon><FirstAidKit /></el-icon></div><div><strong>云脑诊疗</strong><span>NEUSOFT SMART CARE</span></div></div><div class="workspace-label">医生工作站</div><el-menu :default-active="activeMenu" router><el-menu-item index="/workbench"><el-icon><Monitor /></el-icon><span>今日工作台</span></el-menu-item><el-menu-item index="/history"><el-icon><Document /></el-icon><span>历史诊疗记录</span></el-menu-item><el-menu-item index="/profile"><el-icon><User /></el-icon><span>个人中心</span></el-menu-item></el-menu><div class="aside-footer"><div class="secure-icon"><el-icon><Lock /></el-icon></div><div><strong>医疗数据安全连接</strong><span>系统运行正常</span></div><i></i></div></el-aside><el-container><el-header class="layout-header"><div class="header-left"><div class="page-title">{{currentTitle}}</div><div class="breadcrumb">医生工作站 <span>/</span> {{currentTitle}}</div></div><div class="header-right"><div class="date-box"><el-icon><Calendar /></el-icon><div><span>{{weekday}}</span><strong>{{today}}</strong></div></div><div class="header-divider"></div><div class="doctor-mini"><div class="mini-avatar">{{doctorInitial}}</div><div><strong>{{doctorInfo?.name||'医生'}}</strong><span>{{doctorInfo?.title||'专业医生'}} · {{doctorInfo?.departmentName||'未分配科室'}}</span></div></div><el-dropdown trigger="click"><button class="more-button"><el-icon><ArrowDown /></el-icon></button><template #dropdown><el-dropdown-menu><el-dropdown-item @click="router.push('/profile')"><el-icon><User /></el-icon>个人资料</el-dropdown-item><el-dropdown-item divided @click="handleLogout"><el-icon><SwitchButton /></el-icon>退出登录</el-dropdown-item></el-dropdown-menu></template></el-dropdown></div></el-header><el-main class="layout-main"><router-view /></el-main></el-container></el-container></template>
<script setup>import{ref,computed,onMounted,onUnmounted}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessageBox,ElMessage}from'element-plus';import{getDoctorInfo}from'../../api/doctor';const route=useRoute(),router=useRouter(),doctorInfo=ref(null);const activeMenu=computed(()=>route.path),currentTitle=computed(()=>route.meta?.title||'工作台'),doctorInitial=computed(()=>(doctorInfo.value?.name||'医').slice(0,1));const now=new Date(),weekday=now.toLocaleDateString('zh-CN',{weekday:'long'}),today=now.toLocaleDateString('zh-CN',{month:'long',day:'numeric'});const loadDoctor=async()=>{try{const r=await getDoctorInfo();doctorInfo.value=r.data;localStorage.setItem('doctorInfo',JSON.stringify(r.data))}catch(e){}};onMounted(()=>{loadDoctor();window.addEventListener('doctor-profile-updated',loadDoctor)});onUnmounted(()=>window.removeEventListener('doctor-profile-updated',loadDoctor));const handleLogout=async()=>{await ElMessageBox.confirm('确定退出医生工作站吗？','退出登录',{type:'warning',confirmButtonText:'确认退出',cancelButtonText:'暂不退出'});localStorage.removeItem('token');localStorage.removeItem('doctorInfo');ElMessage.success('已安全退出');router.push('/login')}</script>
<style scoped>.layout-container{height:100vh;background:#f3f7f9}.layout-aside{position:relative;display:flex;flex-direction:column;overflow:hidden;background:linear-gradient(180deg,#073b5c 0%,#075866 58%,#087b78 100%);box-shadow:10px 0 35px rgba(17,58,75,.12)}.layout-aside:after{content:'';position:absolute;right:-110px;bottom:90px;width:240px;height:240px;border:1px solid rgba(255,255,255,.08);border-radius:50%;box-shadow:0 0 0 45px rgba(255,255,255,.025)}.brand{position:relative;z-index:1;display:flex;align-items:center;gap:13px;padding:27px 24px 24px;border-bottom:1px solid rgba(255,255,255,.11)}.brand-mark{width:43px;height:43px;display:flex;align-items:center;justify-content:center;border-radius:14px;background:linear-gradient(145deg,#31c0ad,#e9fffb);color:#08636b;font-size:22px;box-shadow:0 8px 20px rgba(0,0,0,.13)}.brand strong,.brand span{display:block}.brand strong{color:#fff;font-size:19px;letter-spacing:1px}.brand span{margin-top:3px;color:rgba(255,255,255,.5);font-size:8px;letter-spacing:1.4px}.workspace-label{padding:23px 25px 10px;color:rgba(255,255,255,.42);font-size:10px;font-weight:700;letter-spacing:2px}.el-menu{position:relative;z-index:1;border:0;background:transparent}.el-menu-item{height:50px;margin:5px 14px;padding:0 16px!important;border-radius:13px;color:rgba(255,255,255,.67);transition:.25s}.el-menu-item:hover{background:rgba(255,255,255,.08);color:#fff}.el-menu-item.is-active{background:linear-gradient(100deg,rgba(51,205,181,.28),rgba(255,255,255,.10));color:#fff;font-weight:650;box-shadow:inset 3px 0 #53dac5}.el-menu-item .el-icon{font-size:19px}.aside-footer{position:relative;z-index:1;display:flex;align-items:center;gap:10px;margin:auto 16px 20px;padding:14px;border:1px solid rgba(255,255,255,.11);border-radius:15px;background:rgba(255,255,255,.07);color:#fff}.secure-icon{width:34px;height:34px;display:flex;align-items:center;justify-content:center;border-radius:10px;background:rgba(74,219,190,.16);color:#61dbc5}.aside-footer strong,.aside-footer span{display:block}.aside-footer strong{font-size:11px}.aside-footer span{margin-top:3px;color:rgba(255,255,255,.47);font-size:9px}.aside-footer i{width:7px;height:7px;margin-left:auto;border-radius:50%;background:#40d39c;box-shadow:0 0 0 4px rgba(64,211,156,.12)}.layout-header{height:74px;display:flex;align-items:center;justify-content:space-between;padding:0 30px;border-bottom:1px solid #e8eff1;background:rgba(255,255,255,.94);box-shadow:0 4px 18px rgba(29,65,79,.045)}.page-title{color:#17384a;font-size:20px;font-weight:750}.breadcrumb{margin-top:4px;color:#a0adb2;font-size:10px}.breadcrumb span{margin:0 5px;color:#c3cdd0}.header-right,.date-box,.doctor-mini{display:flex;align-items:center}.header-right{gap:17px}.date-box{gap:9px;color:#70868e}.date-box>.el-icon{font-size:19px;color:#118d82}.date-box span,.date-box strong,.doctor-mini strong,.doctor-mini span{display:block}.date-box span{font-size:9px}.date-box strong{margin-top:2px;color:#3e5963;font-size:12px}.header-divider{width:1px;height:30px;background:#e6edef}.doctor-mini{gap:10px}.mini-avatar{width:38px;height:38px;display:flex;align-items:center;justify-content:center;border-radius:12px;background:linear-gradient(145deg,#d9f1ed,#b7dfda);color:#087f84;font-size:15px;font-weight:800}.doctor-mini strong{font-size:12px}.doctor-mini span{max-width:170px;margin-top:2px;overflow:hidden;color:#98a7ac;font-size:9px;text-overflow:ellipsis;white-space:nowrap}.more-button{width:31px;height:31px;border:0;border-radius:9px;background:#f1f6f7;color:#6f868d;cursor:pointer}.layout-main{overflow-y:auto;padding:24px 27px 36px;background:radial-gradient(circle at 95% 0,#e5f4f1 0,transparent 25%),#f3f7f9}@media(max-width:900px){.layout-aside{width:76px!important}.brand{padding:22px 16px}.brand>div:last-child,.workspace-label,.el-menu-item span,.aside-footer{display:none}.el-menu-item{justify-content:center;margin:6px 10px;padding:0!important}.header-right .date-box,.header-divider,.doctor-mini>div:last-child{display:none}.layout-main{padding:18px}}</style>
